mapper.select:
/* 요금제/부가서비스/안심보험 등의 카테고리 조회 */ SELECT CTG_CD, CTG_NM FROM MSF_RATE_ADSVC_CTG_BAS A WHERE 1=1
AND A.RATE_ADSVC_DIV_CD = #{prodCtgTypeCd}
AND A.USE_YN = 'Y' AND PSTNG_START_DATE < TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') AND PSTNG_END_DATE >= TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') ORDER BY A.SORT_ODRG

/* 요금제/부가서비스/안심보험 등의 카테고리 상세 조회 */ SELECT DISTINCT B.PROD_ID FROM MSF_RATE_ADSVC_CTG_PROD_REL B WHERE 1=1 AND CTG_CD in ( SELECT CTG_CD FROM MSF_RATE_ADSVC_CTG_BAS A WHERE 1=1
AND A.RATE_ADSVC_DIV_CD = #{prodCtgTypeCd}
AND A.CTG_CD = #{prodCtgId}
AND A.USE_YN = 'Y' AND PSTNG_START_DATE < TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') AND PSTNG_END_DATE >= TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') ) AND USE_YN = 'Y' AND PSTNG_START_DATE < TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') AND PSTNG_END_DATE >= TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
AND PROD_ID IN (SELECT DTL_CD FROM MSF_CD_DTL WHERE CD_GROUP_ID = 'SVCCHG_RATE_CD' AND USE_YN = 'Y' AND TO_CHAR(NOW(),'yyyymmddhh24miss') BETWEEN PSTNG_START_DATE AND PSTNG_END_DATE )

/* 휴대폰 매장 재고 조회 */ SELECT PROD_ID FROM MSF_PROD_STOR_INVENTORY_TXN WHERE 1=1 AND USE_YN = 'Y'
AND STOR_CD = #{orgnId}
AND PSTNG_START_DATE < TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') AND PSTNG_END_DATE >= TO_CHAR(NOW(), 'YYYYMMDDHH24MISS') GROUP BY PROD_ID

/* 휴대폰 일련번호 조회 시 매장재고조회 */
SELECT IMEI
FROM MSF_PROD_STOR_INVENTORY_TXN
WHERE 1=1
    AND USE_YN = 'Y'

        AND STOR_CD = #{orgnId}


        AND PROD_SN = #{prodSn}


        AND PROD_ID = #{prodId}

    AND PSTNG_START_DATE < TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
    AND PSTNG_END_DATE >= TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
